import java.util.*;
import java.util.function.Consumer;

public class SimpleMessageQueue {

    private final Map<String, Queue<String>> topics = new HashMap<>();
    private final Map<String, List<Consumer<String>>> subscribers = new HashMap<>();

    public void publish(String topic, String message) {
        // Add message to the topic queue
        topics.computeIfAbsent(topic, k -> new LinkedList<>()).offer(message);
    }

    public void subscribe(String topic, Consumer<String> handler) {
        // Register a handler for the topic
        subscribers.computeIfAbsent(topic, k -> new ArrayList<>()).add(handler);
    }

    public int processNext(String topic) {
        // Deliver the next message to the next subscriber (round-robin index)
        // Return 1 if delivered, 0 if no messages or no subscribers
        return 0;
    }

    private final Map<String, Integer> roundRobinIndex = new HashMap<>();

    public static void main(String[] args) {
        SimpleMessageQueue mq = new SimpleMessageQueue();
        List<String> received = new ArrayList<>();

        mq.subscribe("orders", msg -> received.add("Consumer1: " + msg));
        mq.subscribe("orders", msg -> received.add("Consumer2: " + msg));

        mq.publish("orders", "Order#1");
        mq.publish("orders", "Order#2");
        mq.publish("orders", "Order#3");

        mq.processNext("orders");
        mq.processNext("orders");
        mq.processNext("orders");

        received.forEach(System.out::println);
    }
}

import java.util.*;
import java.util.stream.*;

public class ServiceCallLogger {

    public record CallRecord(String source, String target, String method, int statusCode) {}

    private final List<CallRecord> logs = new ArrayList<>();

    public void log(String source, String target, String method, int statusCode) {
        logs.add(new CallRecord(source, target, method, statusCode));
    }

    public long totalCalls() {
        return logs.size();
    }

    public double errorRate() {
        // Return percentage of calls with statusCode >= 400
        return 0.0;
    }

    public Map<String, Long> callsPerPair() {
        // Return map of 'source->target' to call count
        return new HashMap<>();
    }

    public static void main(String[] args) {
        ServiceCallLogger logger = new ServiceCallLogger();
        logger.log("gateway", "user-service", "GET", 200);
        logger.log("gateway", "user-service", "POST", 201);
        logger.log("user-service", "auth-service", "POST", 401);
        logger.log("gateway", "order-service", "GET", 500);

        System.out.println("Total: " + logger.totalCalls());
        System.out.printf("Error rate: %.1f%%%n", logger.errorRate());
        System.out.println("Per pair: " + logger.callsPerPair());
    }
}

